import React, { useEffect, useMemo, useState } from "react";
import Sidebar from "../components/Sidebar";
import Navbar from "../components/Navbar";
import API from "../api";
import { useNavigate } from "react-router-dom";

function PredictionForm() {
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem("user"));

  const [symptomList, setSymptomList] = useState([]);
  const [symptoms, setSymptoms] = useState({});
  const [searchTerm, setSearchTerm] = useState("");
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (!user) {
      window.location.href = "/login";
      return;
    }
    fetchSymptoms();
  }, []);

  const fetchSymptoms = async () => {
    try {
      const res = await API.get("/symptoms");
      const list = res.data?.symptoms || [];
      setSymptomList(list);

      const initial = {};
      list.forEach((symptom) => {
        initial[symptom] = 0;
      });
      setSymptoms(initial);
    } catch (error) {
      alert("Failed to load symptoms");
    }
  };

  const selectedCount = Object.values(symptoms).filter((v) => v === 1).length;

  const filteredSymptoms = useMemo(() => {
    return symptomList.filter((symptom) =>
      symptom.replaceAll("_", " ").toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [searchTerm, symptomList]);

  const handleCheckbox = (name) => {
    setSymptoms((prev) => ({
      ...prev,
      [name]: prev[name] === 1 ? 0 : 1
    }));
  };

  const clearAll = () => {
    const cleared = {};
    symptomList.forEach((symptom) => {
      cleared[symptom] = 0;
    });
    setSymptoms(cleared);
    setSearchTerm("");
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (selectedCount === 0) {
      alert("Please select at least one symptom");
      return;
    }

    try {
      setLoading(true);

      const res = await API.post("/predict", {
        patient_name: user?.name || "Patient",
        symptoms
      });

      localStorage.setItem("prediction_result", JSON.stringify(res.data));
      navigate("/result");
    } catch (error) {
      alert(error.response?.data?.error || "Prediction failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="dashboard-layout">
      <Sidebar role="patient" />

      <div className="main-content">
        <Navbar
          title="AI Prediction Form"
          subtitle="Select symptoms and let AI recommend the right doctor"
        />

        <div className="row g-4">
          <div className="col-lg-8">
            <div className="form-box">
              <div className="d-flex justify-content-between align-items-center flex-wrap gap-2 mb-3">
                <div>
                  <h4 className="mb-1">Symptom Selection</h4>
                  <p className="text-muted mb-0">
                    Choose all symptoms that match the patient condition
                  </p>
                </div>

                <div className="badge bg-primary fs-6 px-3 py-2 rounded-pill">
                  Selected: {selectedCount}
                </div>
              </div>

              <div className="mb-4">
                <input
                  type="text"
                  className="form-control"
                  placeholder="Search symptom..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>

              <form onSubmit={handleSubmit}>
                <div className="row">
                  {filteredSymptoms.map((symptom, index) => (
                    <div className="col-md-6 mb-3" key={index}>
                      <div
                        className={`form-check border rounded-4 p-3 h-100 ${
                          symptoms[symptom] === 1 ? "border-primary shadow-sm" : ""
                        }`}
                        style={{
                          cursor: "pointer",
                          transition: "0.2s ease"
                        }}
                        onClick={() => handleCheckbox(symptom)}
                      >
                        <input
                          className="form-check-input"
                          type="checkbox"
                          checked={symptoms[symptom] === 1}
                          onChange={() => handleCheckbox(symptom)}
                          id={symptom}
                        />
                        <label
                          className="form-check-label ms-2 text-capitalize"
                          htmlFor={symptom}
                          style={{ cursor: "pointer" }}
                        >
                          {symptom.replaceAll("_", " ")}
                        </label>
                      </div>
                    </div>
                  ))}

                  {filteredSymptoms.length === 0 && (
                    <div className="col-12">
                      <div className="alert alert-warning rounded-4">
                        No symptoms found for your search.
                      </div>
                    </div>
                  )}
                </div>

                <div className="d-flex gap-3 mt-4 flex-wrap">
                  <button className="btn btn-premium px-4" disabled={loading}>
                    {loading ? "Predicting..." : "Predict Doctor"}
                  </button>

                  <button
                    type="button"
                    className="btn btn-outline-secondary px-4"
                    onClick={clearAll}
                    disabled={loading}
                  >
                    Clear All
                  </button>
                </div>
              </form>
            </div>
          </div>

          <div className="col-lg-4">
            <div className="dashboard-card">
              <h5 className="mb-3">AI Form Tips</h5>

              <ul className="text-muted ps-3">
                <li>Select multiple symptoms for better prediction accuracy</li>
                <li>Use search bar to quickly find a symptom</li>
                <li>AI will recommend doctor specialization automatically</li>
                <li>PDF report can be downloaded after prediction</li>
              </ul>

              <hr />

              <h6 className="mb-2">Current Patient</h6>
              <p className="mb-1"><strong>Name:</strong> {user?.name}</p>
              <p className="mb-0"><strong>Email:</strong> {user?.email}</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default PredictionForm;
